using System.ComponentModel.DataAnnotations;

namespace sv_9675beb028974a15a9c0e84aabdf40aa.Models;

public enum ProductCategory
{
    Electronics,
    Clothing,
    Food,
    Other
}

public class Product
{
    public int Id { get; set; }

    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100, MinimumLength = 2, ErrorMessage = "Name must be between 2 and 100 characters.")]
    public string? Name { get; set; }

    [Required(ErrorMessage = "Quantity is required.")]
    [Range(0, 10000, ErrorMessage = "Quantity must be between 0 and 10,000.")]
    public int Quantity { get; set; }

    [Required(ErrorMessage = "Unit Price is required.")]
    [Range(0.01, 99999.99, ErrorMessage = "Unit Price must be between 0.01 and 99,999.99.")]
    public decimal UnitPrice { get; set; }

    [Required(ErrorMessage = "Category is required.")]
    public ProductCategory Category { get; set; }
}

using sv_9675beb028974a15a9c0e84aabdf40aa.Models;

namespace sv_9675beb028974a15a9c0e84aabdf40aa.Services;

public class InventoryService
{
    private readonly Lock _lock = new();
    private readonly List<Product> _products;
    private int _nextId;

    public InventoryService()
    {
        _products = new List<Product>
        {
            new() { Id = 1, Name = "Wireless Headphones", Quantity = 45, UnitPrice = 59.99m, Category = ProductCategory.Electronics },
            new() { Id = 2, Name = "Cotton T-Shirt", Quantity = 200, UnitPrice = 14.99m, Category = ProductCategory.Clothing },
            new() { Id = 3, Name = "Organic Coffee Beans", Quantity = 80, UnitPrice = 12.50m, Category = ProductCategory.Food },
            new() { Id = 4, Name = "USB-C Charging Cable", Quantity = 150, UnitPrice = 9.99m, Category = ProductCategory.Electronics },
            new() { Id = 5, Name = "Winter Jacket", Quantity = 30, UnitPrice = 89.95m, Category = ProductCategory.Clothing },
            new() { Id = 6, Name = "Dark Chocolate Bar", Quantity = 120, UnitPrice = 4.99m, Category = ProductCategory.Food },
        };
        _nextId = 7;
    }

    public Task<List<Product>> GetAllAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_products.Select(p => new Product
            {
                Id = p.Id,
                Name = p.Name,
                Quantity = p.Quantity,
                UnitPrice = p.UnitPrice,
                Category = p.Category
            }).ToList());
        }
    }

    public Task AddAsync(Product product)
    {
        lock (_lock)
        {
            product.Id = _nextId++;
            _products.Add(new Product
            {
                Id = product.Id,
                Name = product.Name,
                Quantity = product.Quantity,
                UnitPrice = product.UnitPrice,
                Category = product.Category
            });
        }
        return Task.CompletedTask;
    }

    public Task UpdateAsync(Product product)
    {
        lock (_lock)
        {
            var existing = _products.FirstOrDefault(p => p.Id == product.Id);
            if (existing is not null)
            {
                existing.Name = product.Name;
                existing.Quantity = product.Quantity;
                existing.UnitPrice = product.UnitPrice;
                existing.Category = product.Category;
            }
        }
        return Task.CompletedTask;
    }
}

