<div class="card mb-4">
    <div class="card-header">
        <h5 class="mb-0">Quick Add Product</h5>
    </div>
    <div class="card-body">
        <EditForm Model="NewProduct" OnValidSubmit="HandleQuickAdd" FormName="quick-add" Enhance>
            <DataAnnotationsValidator />
            <ValidationSummary />

            <div class="row g-3 align-items-end">
                <div class="col-md-3">
                    <label class="form-label">Name</label>
                    <InputText @bind-Value="NewProduct!.Name" class="form-control" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Quantity</label>
                    <InputNumber @bind-Value="NewProduct!.Quantity" class="form-control" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Unit Price</label>
                    <InputNumber @bind-Value="NewProduct!.UnitPrice" class="form-control" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Category</label>
                    <InputSelect @bind-Value="NewProduct!.Category" class="form-select">
                        @foreach (var cat in Enum.GetValues<ProductCategory>())
                        {
                            <option value="@cat">@cat</option>
                        }
                    </InputSelect>
                </div>
                <div class="col-md-2">
                    <button type="submit" class="btn btn-primary w-100">Add</button>
                </div>
            </div>
        </EditForm>
    </div>
</div>

@* PART 2 — Product table with inline editing *@
<table class="table table-striped">
    <thead>
        <tr>
            <th>ID</th>
            <th>Name</th>
            <th>Quantity</th>
            <th>Unit Price</th>
            <th>Category</th>
            <th>Actions</th>
        </tr>
    </thead>
    <tbody>
        @foreach (var product in products)
        {
            if (editId == product.Id)
            {
                @* Interactive island: this component gets its own @rendermode *@
                <ProductEditRow ProductId="product.Id" @rendermode="InteractiveServer" />
            }
            else
            {
                <tr>
                    <td>@product.Id</td>
                    <td>@product.Name</td>
                    <td>@product.Quantity</td>
                    <td>@product.UnitPrice.ToString("C")</td>
                    <td>@product.Category</td>
                    <td>
                        @* Edit triggers a navigation with query param — stays in static SSR *@
                        <a href="/inventory?edit=@product.Id" class="btn btn-sm btn-outline-secondary">Edit</a>
                    </td>
                </tr>
            }
        }
    </tbody>
</table>

@code {
    private List<Product> products = new();
    private int? editId;

    [SupplyParameterFromForm(FormName = "quick-add")]
    private Product? NewProduct { get; set; }

    [SupplyParameterFromQuery(Name = "edit")]
    private int? EditQuery { get; set; }

    protected override void OnInitialized()
    {
        NewProduct ??= new();
    }

    protected override async Task OnInitializedAsync()
    {
        editId = EditQuery;
        products = await InventoryService.GetAllAsync();
    }

    private async Task HandleQuickAdd()
    {
        await InventoryService.AddAsync(NewProduct!);
        NewProduct = new();
        products = await InventoryService.GetAllAsync();
    }
}
"}

